"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { products as sourceProducts, getProductById, type Product, type ProductFilters } from "@/data/products";

const imageCache = new Map<number, string>();

async function probe(url: string): Promise<boolean> {
  try {
    const res = await fetch(url, { method: "HEAD", cache: "no-store" });
    return res.ok;
  } catch {
    return false;
  }
}

async function resolveImageForId(id: number): Promise<string | null> {
  if (imageCache.has(id)) return imageCache.get(id)!;
  const exts = ["jpeg", "jpg", "png", "webp", "gif"] as const;
  const variants = ["", "b", "c"] as const;
  for (const v of variants) {
    for (const ext of exts) {
      const url = `/products/${id}${v}.${ext}`;
      if (await probe(url)) {
        imageCache.set(id, url);
        return url;
      }
    }
  }
  return null;
}

export function useProducts(filters?: ProductFilters) {
  const [all, setAll] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;
    async function build() {
      const updated = await Promise.all(
        sourceProducts.map(async (p) => {
          const found = await resolveImageForId(p.id);
          return { ...p, imageUrl: found ?? p.imageUrl } as Product;
        })
      );
      if (mounted.current) {
        setAll(updated);
        setIsLoading(false);
      }
    }
    build();
    return () => {
      mounted.current = false;
    };
  }, []);

  const data = useMemo(() => {
    let result = [...all];
    if (filters?.category) result = result.filter((p) => p.category === filters.category);
    if (filters?.subcategory) result = result.filter((p) => p.subcategory === filters.subcategory);
    if (filters?.isFeatured !== undefined) result = result.filter((p) => p.isFeatured === filters.isFeatured);
    return result;
  }, [all, filters?.category, filters?.subcategory, filters?.isFeatured]);

  return { data, isLoading };
}

export function useProduct(id: number) {
  const { data, isLoading } = useProducts();
  const item = useMemo(() => data.find((p) => p.id === id) ?? null, [data, id]);
  return { data: item, isLoading };
}

export type { Product };
